import React, { useEffect, useState } from "react";
import { View, Text, StyleSheet, Image, Pressable } from "react-native";
import { Audio } from "expo-av";
import Ionicons from "@expo/vector-icons/Ionicons";
import { Slider } from "@react-native-assets/slider";
import { CircularSlider } from "react-web-circular-slider";

export default function ShazamScreen({ route, navigation }) {
  const { title = "", image = "", id = "" } = route.params || {};
  const [icon, setIcon] = useState("play");
  const [playing, setPlaying] = useState(false);
  const [sound, setSound] = useState();
  const [positionMillis, setPositionMillis] = useState(0);
  const [durationMillis, setDurationMillis] = useState(0);
  const audiourl = `https://musicapi.x007.workers.dev/fetch?id=${id}`;
  const [vol, setVol] = useState(0.5);
  const startAngle = 0
  const angleLength = 2
  const dailogstuff = () => {
    alert("coming soon");
  };

  useEffect(() => {
    const startAudio = async () => {
      if (!id) {
        // If ID is not available, return without loading the audio
        return;
      }

      setIcon("pause");
      if (sound) {
        // Unload the existing sound
        await sound.unloadAsync();
      }
      // Create a new sound instance with the updated song URL
      const { sound: newSound } = await Audio.Sound.createAsync(
        { uri: audiourl },
        { shouldPlay: true },
        onPlaybackStatusUpdate
      );
      volup(0.3)
      setSound(newSound);
      setPlaying(true);
    };

    startAudio(); // Call the function to start playing the audio

    // Clean up function
    return () => {
      // Unload the sound when the component is unmounted
      if (sound) {
        sound.unloadAsync();
      }
    };
  }, [id]); // Add 'id' as a dependency to trigger the effect when it changes

 const startAudio = async () => {
   if (!id) {
     // If ID is not available, return without loading the audio
     return;
   }

   if (playing) {
     // If audio is already playing, pause it
     await sound.pauseAsync();
     setPlaying(false);
     setIcon("play-outline");
   } else {
     setIcon("pause");
     if (sound) {
       // Unload the existing sound
       await sound.unloadAsync();
     }
     // Create a new sound instance with the updated song URL
     const { sound: newSound, status } = await Audio.Sound.createAsync(
       { uri: audiourl },
       { shouldPlay: true },
       onPlaybackStatusUpdate
     );
     setSound(newSound);
     setPlaying(true);
     setPositionMillis(status?.playableDurationMillis || 0);
   }
 };


const volup = async(value) =>{;
   setVol(value.toFixed(1));
   if (sound) {
    await sound.setVolumeAsync(value); // Adjust the volume
  }
}

  const onPlaybackStatusUpdate = (status) => {
    if (status.isLoaded && status.isPlaying) {
      setPositionMillis(status.positionMillis);
      setDurationMillis(status.durationMillis);
    }
  };

  return (
    <View style={styles.container}>
      <View style={styles.playbox}>
        {image ? (
          <Image
            resizeMode="contain"
            style={styles.music}
            source={{ uri: image }}
          />
        ) : (
          <Image
            resizeMode="contain"
            style={styles.music}
            source={require("./images/icon.png")} // Replace with your own placeholder image
          />
        )}
        <View style={styles.title}>
          {title ? (
            <Text style={styles.textcolor}>{title}</Text>
          ) : (
            <View style={styles.title}>
              <Text style={styles.textcolor}>
                No Title Available Play A Song First
              </Text>
              <Pressable
                onPress={() => navigation.navigate("Home")}
                style={styles.btn}
              >
                <Text style={styles.btntxt}>Go Back To Home</Text>
              </Pressable>
            </View>
            
          )}
        </View>
        {title && id && (
          <>
            <Slider
              style={styles.slider}
              minimumValue={0}
              maximumValue={durationMillis}
              value={positionMillis}
              minimumTrackTintColor="#FFFFFF"
              maximumTrackTintColor="#8E8787"
              thumbTintColor={"purple"}
            />
            
            <View style={styles.flex1}>
              <View style={styles.playerlay}>
                <Pressable style={styles.player} onPress={dailogstuff}>
                  <Ionicons name="play-back" size={32} color="#ffffff" />
                </Pressable>
                <Pressable style={styles.player} onPress={startAudio}>
                  <Ionicons name={icon} size={32} color="#ffffff" />
                </Pressable>
                <Pressable style={styles.player} onPress={dailogstuff}>
                  <Ionicons name="play-forward" size={32} color="#ffffff" />
                </Pressable>
              </View>
            </View>
             <View style={styles.playervol}>
                <Ionicons style={styles.icon} name="volume-low-outline" size={32} color="#ffffff" />
                <Slider
                  style={styles.volslider}
                  minimumValue={0}
                  maximumValue={1.0}
                  value={0.3}
                  minimumTrackTintColor="#FFFFFF"
                  maximumTrackTintColor="#8E8787"
                  thumbTintColor={"purple"}
                  onValueChange={(value) => volup(value)}
                />
              </View>
          </>
        )}
      </View>
      {id && (
        <View style={styles.id}>
          <Text style={styles.idtxt}>Song ID: {id}</Text>
          <Text style={styles.idtxt}>Position: {positionMillis} ms</Text>
        </View>
      )}
    </View>
  ); 
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    padding: 10,
    backgroundColor: "#090909",
    alignContent: "center",
  },
  flex1: {
    flex: 1,
    flexDirection: "row",
    marginBottom: 55,
  },
  title: {
    margin: 5,
    padding: 10,
  },
  btntxt: {
    color: "white",
    fontSize: 20,
    textAlign: "center",
  },
  id: {
    alignSelf: "flex-start",
    textAlign: "bottom-left",
  },
  playerlay: {
    marginBottom: 60,
    flexDirection: "row",
    justifyContent: "center",
    alignContent:'center',
  },
  player: {
    flex: 1,
    margin: 5,
    height:55,
    backgroundColor: "#393639",
    padding: 10,
    borderRadius: 90,
  },
  playervol: {
    margin: 5,
    flexDirection: "row",
    justifyContent: "center",
    alignContent:'center',
  },
  btn: {
    margin: 5,
    backgroundColor: "#393639",
    padding: 10,
    borderRadius: 10,
  },
  playbox: {
    flex: 1,
    padding: 10,
    backgroundColor: "#090909",
    alignItems: "center",
    justifyContent: "center",
  },
  textcolor: {
    color: "white",
    fontSize: 30,
    marginBottom: 5,
    marginTop: 5,
  },
  idtxt: {
    color: "#8e8787",
    fontSize: 10,
  },
  music: {
    width: "100%",
    height: 300,
    margin: 5,
  },
  slider: {
    width: "100%",
    height: 50,
    marginBottom: 30,
  },
  volslider: {
    width: 150,
    height: 50,
    marginBottom: 50,
  },
  icon:{
    marginTop:8,
    marginRight:5,
  },
});
