export default function HomeScreen({navigation}){
    const [data,setData]=useState([]);
const [search, setSearch] = useState('');
const flatListRef = React.useRef()
    //const [likedsongs,setlikedsongs] = useState([]);

  useEffect(() => {getsongs(`https://musicapi.x007.workers.dev/search?q=top hits&searchEngine=seevn`);
  }, []);
  const getsongs = async(aurl) =>{
    let url = aurl;
    let result = await fetch(url);
    result = await result.json();
    setData(result.response)
    flatListRef.current.scrollToOffset({ animated: true, offset: 0 });
}
  //const likesong = (item) =>{
    //setlikedsongs(item);
    //navigation.navigate("Liked Songs", {
      //likedsongs
    //});
    //console.log(likedsongs);
  //}
  const searchsong = () => { 
    getsongs(
      `https://musicapi.x007.workers.dev/search?q=${search}&searchEngine=ressa`
    );
    flatListRef.current.scrollToOffset({ animated: true, offset: 0 })
  }
const updateSearch = (text) => {
    setSearch(text);
  };
    return (
      <View style={styles.container}>
        <View style={styles.search}>
          <TextInput
            onSubmitEditing={(event) =>
              getsongs(
                `https://musicapi.x007.workers.dev/search?q=${event.nativeEvent.text}&searchEngine=ressa`
              )
            }
            onChangeText={(text) => updateSearch(text)}
            style={styles.tinput}
            placeholderTextColor={"white"}
            placeholder="Search Song or Album..."
          ></TextInput>
          <Pressable onPress={searchsong} style={styles.button}>
            <Text style={styles.buttontxt}>Search</Text>
          </Pressable>
        </View>
        <StatusBar style="auto" />
        {data.length ? (
          <FlatList
            data={data}
            ref={flatListRef}
            contentContainerStyle={{ paddingVertical: 16 }}
            contentInsetAdjustmentBehavior="never"
            snapToAlignment="center"
            style={styles.slide}
            decelerationRate="fast"
            automaticallyAdjustContentInsets={false}
            showsHorizontalScrollIndicator={false}
            showsVerticalScrollIndicator={false}
            scrollEventThrottle={1}
            pagingEnabled
            renderItem={({ item }) => (
              <View>
                <View style={styles.card}>
                  <Image
                    style={styles.img}
                    source={{ uri: `${item.img}` }}
                  ></Image>

                  <View style={styles.cardtxtcontain}>
                    <Text style={styles.cardtxt}>{item.title}</Text>
                    
                  </View>

                  <Pressable
                    style={styles.playbutton}
                    onPress={() =>
                      navigation.navigate("Now Playing", {
                        title: item.title,
                        image: item.img,
                        id: item.id,
                      })
                    }
                  >
                    <Text style={styles.buttontxt}>Play</Text>
                  </Pressable>
                </View>
              </View>
            )}
          />
        ) : null}
      </View>
    );
}
